'use client'
import { useEffect, useState, Suspense } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import { supabase } from '@/lib/supabase'

const HERO_IMAGE = 'data:image/jpeg;base64,'

function LoginContent() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const [loading, setLoading] = useState(true)
  const [email, setEmail] = useState('')
  const [sent, setSent] = useState(false)
  const [sending, setSending] = useState(false)
  const [error, setError] = useState('')
  const joinCode = searchParams?.get('code') || ''

  useEffect(() => {
    supabase.auth.getUser().then(({ data: { user } }) => {
      if (user) router.push('/home')
      else setLoading(false)
    })
  }, [router])

  async function sendMagicLink() {
    if (!email.trim() || !email.includes('@')) { setError('הכנס כתובת מייל תקינה'); return }
    setSending(true); setError('')
    const redirectTo = joinCode
      ? `https://seder-beseder.com/home?code=${joinCode}`
      : 'https://seder-beseder.com/home'
    const { error: err } = await supabase.auth.signInWithOtp({
      email: email.trim(),
      options: { emailRedirectTo: redirectTo }
    })
    if (err) { setError('שגיאה: ' + err.message); setSending(false); return }
    setSent(true); setSending(false)
  }

  async function signInWithGoogle() {
    const redirectTo = joinCode
      ? `https://seder-beseder.com/home?code=${joinCode}`
      : 'https://seder-beseder.com/home'
    await supabase.auth.signInWithOAuth({ provider: 'google', options: { redirectTo } })
  }

  if (loading) return (
    <div style={{ minHeight:'100vh', background:'#192542', display:'flex', alignItems:'center', justifyContent:'center' }}>
      <div style={{ fontSize:'2rem' }}>⏳</div>
    </div>
  )

  return (
    <div style={{ minHeight:'100vh', background:'#f5f0e8', fontFamily:'Heebo, sans-serif', direction:'rtl' }}>

      {/* NAV */}
      <nav style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'14px 20px', background:'white', borderBottom:'1px solid #eee', position:'sticky', top:0, zIndex:100 }}>
        <span style={{ fontSize:'17px', fontWeight:900, color:'#192542' }}>סדר בסדר 🏠</span>
        <button onClick={() => document.getElementById('login-card')?.scrollIntoView({ behavior:'smooth' })}
          style={{ background:'#192542', color:'white', border:'none', borderRadius:'100px', padding:'9px 18px', fontSize:'13px', fontWeight:700, cursor:'pointer', fontFamily:'Heebo, sans-serif' }}>
          כניסה לאפליקציה
        </button>
      </nav>

      {/* HERO IMAGE */}
      <div style={{ maxWidth:'500px', margin:'0 auto' }}>
        <img src={HERO_IMAGE} alt="סדר בסדר" style={{ width:'100%', display:'block' }} />
        <div style={{ textAlign:'center', padding:'20px 20px 0', background:'#f5f0e8' }}>
          <button onClick={() => document.getElementById('login-card')?.scrollIntoView({ behavior:'smooth' })}
            style={{ display:'inline-flex', alignItems:'center', gap:'8px', background:'#C99A2E', color:'white', border:'none', borderRadius:'16px', padding:'15px 30px', fontSize:'16px', fontWeight:800, cursor:'pointer', fontFamily:'Heebo, sans-serif', boxShadow:'0 8px 24px rgba(201,154,46,.4)' }}>
            ← התחילו עכשיו — בחינם
          </button>
          <p style={{ fontSize:'12px', color:'#aaa', marginTop:'8px', paddingBottom:'16px' }}>ללא הורדה · עובד על כל טלפון</p>
        </div>
      </div>

      {/* QUESTIONS */}
      <div style={{ padding:'36px 20px', maxWidth:'500px', margin:'0 auto' }}>
        <h2 style={{ fontSize:'26px', fontWeight:900, color:'#192542', textAlign:'center', marginBottom:'6px' }}>מכירים את זה?</h2>
        <p style={{ fontSize:'14px', color:'#999', textAlign:'center', marginBottom:'20px' }}>שאלות שחוזרות כל חג מחדש</p>
        {['"איפה חגגנו פסח בשנה שעברה?"','"עם איזה צד של המשפחה היינו בראש השנה?"','"מי אירח בפעם האחרונה?"','"למה תמיד אותם אנשים מארחים?"','"מי לא הגיע כבר שני חגים?"','"איך מחלקים בצורה הוגנת?"'].map(q => (
          <div key={q} style={{ background:'#FEF0EB', borderRadius:'14px', padding:'15px 18px', marginBottom:'8px', fontSize:'15px', fontWeight:600, color:'#192542', textAlign:'center', borderRight:'3px solid #F07A55' }}>{q}</div>
        ))}
      </div>

      {/* FEATURES */}
      <div style={{ background:'#192542', padding:'36px 20px' }}>
        <div style={{ maxWidth:'500px', margin:'0 auto' }}>
          <h2 style={{ color:'white', fontSize:'26px', fontWeight:900, textAlign:'center', marginBottom:'6px' }}>הפתרון</h2>
          <p style={{ color:'rgba(255,255,255,.45)', fontSize:'14px', textAlign:'center', marginBottom:'20px' }}>אפליקציה אחת שזוכרת הכל, מתכננת בצורה הוגנת, ומפחיתה דרמה</p>
          {[['📅','תיעוד חגים','שמרו את כל החגים והאירועים המשפחתיים במקום אחד'],['👥','ניהול משפחה','עקבו אחרי מי אירח, מי הגיע, ומי חסר'],['💡','המלצות חכמות','קבלו הצעות הוגנות למארחים ולתכנון חגים'],['🧺','מי מביא מה','תאמו מי מביא מה לכל חג בקלות ובשקיפות']].map(([icon, title, desc]) => (
            <div key={String(title)} style={{ background:'rgba(255,255,255,.07)', border:'1px solid rgba(255,255,255,.1)', borderRadius:'16px', padding:'15px 16px', marginBottom:'10px', display:'flex', alignItems:'center', gap:'14px' }}>
              <div style={{ width:'42px', height:'42px', borderRadius:'12px', background:'rgba(240,122,85,.2)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'19px', flexShrink:0 }}>{icon}</div>
              <div><div style={{ color:'white', fontSize:'15px', fontWeight:700, marginBottom:'3px' }}>{String(title)}</div><div style={{ color:'rgba(255,255,255,.45)', fontSize:'13px' }}>{String(desc)}</div></div>
            </div>
          ))}
        </div>
      </div>

      {/* WHY */}
      <div style={{ background:'linear-gradient(135deg,#192542,#1e3a6e)', padding:'36px 20px' }}>
        <div style={{ maxWidth:'500px', margin:'0 auto' }}>
          <h2 style={{ color:'white', fontSize:'26px', fontWeight:900, textAlign:'center', marginBottom:'20px' }}>למה משפחות אוהבות את סדר בסדר?</h2>
          {[['💛','מפחית מתחים ודרמה לפני חגים'],['⚖️','מבטיח חלוקה הוגנת בין הצדדים'],['🧠','זוכר מה שכולם שוכחים'],['👨‍👩‍👧‍👦','מתאים למשפחות מורחבות ומורכבות'],['📱','עובד על כל טלפון, בלי להוריד אפליקציה'],['🎁','חינם לחלוטין לכל המשפחה']].map(([icon, text], i, arr) => (
            <div key={String(text)} style={{ display:'flex', alignItems:'center', gap:'12px', padding:'12px 0', borderBottom: i < arr.length-1 ? '1px solid rgba(255,255,255,.07)' : 'none' }}>
              <span style={{ fontSize:'20px', width:'32px', textAlign:'center', flexShrink:0 }}>{icon}</span>
              <p style={{ color:'rgba(255,255,255,.85)', fontSize:'14px', fontWeight:600 }}>{String(text)}</p>
            </div>
          ))}
        </div>
      </div>

      {/* STEPS */}
      <div style={{ background:'#f0ede3', padding:'36px 20px' }}>
        <div style={{ maxWidth:'500px', margin:'0 auto' }}>
          <h2 style={{ fontSize:'26px', fontWeight:900, color:'#192542', textAlign:'center', marginBottom:'20px' }}>איך מתחילים?</h2>
          {[['נכנסים עם מייל או Google','הרשמה מהירה בלי סיסמאות — רק מייל וקישור'],['מזמינים את המשפחה','שולחים קישור בוואטסאפ — כל אחד נכנס בקלות'],['מתחילים לתעד','מוסיפים אירועים, בני משפחה, ומי מביא מה'],['מקבלים תובנות','האפליקציה מנתחת ומציעה חלוקה הוגנת לחג הבא']].map(([title, desc], i) => (
            <div key={String(title)} style={{ display:'flex', gap:'14px', alignItems:'flex-start', marginBottom:'16px' }}>
              <div style={{ width:'34px', height:'34px', borderRadius:'50%', background:'#192542', color:'white', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'14px', fontWeight:800, flexShrink:0, marginTop:'2px' }}>{i+1}</div>
              <div><div style={{ fontSize:'15px', fontWeight:800, color:'#192542', marginBottom:'3px' }}>{String(title)}</div><div style={{ fontSize:'13px', color:'#777', lineHeight:1.5 }}>{String(desc)}</div></div>
            </div>
          ))}
        </div>
      </div>

      {/* LOGIN CARD */}
      <div id="login-card" style={{ background:'linear-gradient(135deg,#192542,#1e3a6e)', padding:'44px 20px' }}>
        <div style={{ maxWidth:'380px', margin:'0 auto' }}>
          <h2 style={{ color:'white', fontSize:'24px', fontWeight:900, textAlign:'center', marginBottom:'6px' }}>
            {joinCode ? 'כניסה להצטרפות 🎉' : 'מוכנים לחגוג בלי דרמה?'}
          </h2>
          <p style={{ color:'rgba(255,255,255,.45)', fontSize:'13px', textAlign:'center', marginBottom:'22px' }}>הכנס מייל וקבל קישור כניסה</p>

          <div style={{ background:'rgba(255,255,255,.07)', border:'1px solid rgba(255,255,255,.1)', borderRadius:'24px', padding:'24px' }}>
            {sent ? (
              <div style={{ textAlign:'center' }}>
                <div style={{ fontSize:'48px', marginBottom:'14px' }}>📧</div>
                <h3 style={{ color:'white', fontSize:'18px', fontWeight:800, marginBottom:'10px' }}>בדוק את המייל שלך!</h3>
                <p style={{ color:'rgba(255,255,255,.5)', fontSize:'14px', lineHeight:1.6, marginBottom:'16px' }}>שלחנו קישור כניסה ל-<br/><strong style={{ color:'white' }}>{email}</strong></p>
                <button onClick={() => setSent(false)} style={{ background:'none', border:'none', color:'rgba(255,255,255,.4)', fontSize:'13px', cursor:'pointer', fontFamily:'Heebo, sans-serif', textDecoration:'underline' }}>שלח שוב</button>
              </div>
            ) : (
              <>
                <input type="email" placeholder="הכנס כתובת מייל" value={email}
                  onChange={e => { setEmail(e.target.value); setError('') }}
                  onKeyDown={e => e.key === 'Enter' && sendMagicLink()}
                  style={{ width:'100%', padding:'13px 16px', background:'rgba(255,255,255,.08)', border:'1.5px solid rgba(255,255,255,.15)', borderRadius:'14px', fontSize:'15px', fontFamily:'Heebo, sans-serif', direction:'rtl', color:'white', outline:'none', marginBottom:'10px' }} />
                {error && <div style={{ background:'rgba(224,101,95,.15)', border:'1px solid rgba(224,101,95,.3)', borderRadius:'12px', padding:'10px', marginBottom:'10px', color:'#ffb3b0', fontSize:'13px', textAlign:'center' }}>⚠️ {error}</div>}
                <button onClick={sendMagicLink} disabled={sending}
                  style={{ width:'100%', padding:'14px', background:'#F07A55', border:'none', borderRadius:'14px', color:'white', fontSize:'15px', fontWeight:700, cursor:'pointer', fontFamily:'Heebo, sans-serif', opacity:sending?0.7:1, marginBottom:'10px' }}>
                  {sending ? '📤 שולח...' : '📧 שלח קישור כניסה'}
                </button>
                <div style={{ display:'flex', alignItems:'center', gap:'10px', margin:'14px 0' }}>
                  <div style={{ flex:1, height:'1px', background:'rgba(255,255,255,.1)' }} />
                  <span style={{ color:'rgba(255,255,255,.3)', fontSize:'12px' }}>או</span>
                  <div style={{ flex:1, height:'1px', background:'rgba(255,255,255,.1)' }} />
                </div>
                <button onClick={signInWithGoogle}
                  style={{ width:'100%', padding:'13px', background:'white', border:'none', borderRadius:'14px', display:'flex', alignItems:'center', justifyContent:'center', gap:'10px', cursor:'pointer', fontSize:'14px', fontWeight:700, color:'#333', fontFamily:'Heebo, sans-serif' }}>
                  <svg width="18" height="18" viewBox="0 0 24 24">
                    <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                    <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                    <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                    <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
                  </svg>
                  כניסה עם Google
                </button>
              </>
            )}
          </div>
        </div>
      </div>

      <footer style={{ background:'#192542', padding:'16px 20px', textAlign:'center', borderTop:'1px solid rgba(255,255,255,.06)' }}>
        <p style={{ color:'rgba(255,255,255,.25)', fontSize:'12px' }}>סדר בסדר · עם ❤️ למשפחות ישראל</p>
      </footer>
    </div>
  )
}

export default function RootPage() {
  return (
    <Suspense fallback={<div style={{ minHeight:'100vh', background:'#192542', display:'flex', alignItems:'center', justifyContent:'center' }}><div style={{ fontSize:'2rem' }}>⏳</div></div>}>
      <LoginContent />
    </Suspense>
  )
}
